sql:
SELECT model_name
FROM hvac_models
WHERE seer_rating_max > 18;

SELECT model_id, COUNT(service_id) AS service_count
FROM service_history
GROUP BY model_id;

SELECT model_name
FROM hvac_models
WHERE seer_rating_max = (SELECT MAX(seer_rating_max) FROM hvac_models);

SELECT AVG(efficiency_rating) AS average_efficiency_rating
FROM performance_metrics
WHERE model_id IN (SELECT model_id FROM customer_feedback);

external_knowledge:
- A high customer rating is defined as 4 or more stars out of 5; 
- The efficiency rating is based on the SEER (Seasonal Energy Efficiency Ratio) and EER (Energy Efficiency Ratio) of the HVAC models; 
- Recent servicing refers to any maintenance or repair work done on or after January 1, 2023.

sql:
SELECT COUNT(*) AS active_model_count
FROM hvac_models
WHERE is_discontinued = 0;
